import{_ as r,o as d,c as a,a7 as e}from"./chunks/framework.C5fSpjcB.js";const _=JSON.parse('{"title":"银芯通信","description":"","frontmatter":{},"headers":[],"relativePath":"story/silver-core.md","filePath":"zh/story/silver-core.md","lastUpdated":1775394001000}'),o={name:"story/silver-core.md"};function l(s,t,i,n,c,h){return d(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="银芯通信" tabindex="-1">银芯通信 <a class="header-anchor" href="#银芯通信" aria-label="Permalink to &quot;银芯通信&quot;">​</a></h1><p>银芯通信是忘却前夜中的唤醒体好感度/羁绊系统。</p><h2 id="系统概述" tabindex="-1">系统概述 <a class="header-anchor" href="#系统概述" aria-label="Permalink to &quot;系统概述&quot;">​</a></h2><p>通过银芯通信，守密人（玩家）可以与唤醒体建立更深的羁绊关系，解锁专属剧情、语音和其他奖励。</p><p>「银芯」是一种通信装置，让守密人能够与唤醒体的心灵和记忆建立连结。这一系统与游戏「记忆与遗忘」的核心主题紧密相连——通过银芯通信，玩家不仅能提升角色实力，更能深入了解每位唤醒体背后的故事与秘密。</p><h2 id="好感度提升方式" tabindex="-1">好感度提升方式 <a class="header-anchor" href="#好感度提升方式" aria-label="Permalink to &quot;好感度提升方式&quot;">​</a></h2><ul><li><strong>赠送礼物</strong> -- 赠送唤醒体喜欢的物品，可获得大量好感度。不同唤醒体有各自的喜好偏向，中性礼物仅获少量好感，不喜欢的礼物可能无收益</li><li><strong>互动对话</strong> -- 通过银芯通信界面与唤醒体进行日常互动，每日积少成多</li><li><strong>编入队伍</strong> -- 将唤醒体编入战斗队伍出战，通过共同作战经历缓慢积累好感</li><li><strong>完成任务</strong> -- 完成与唤醒体背景故事相关的专属任务，可获得大量好感度提升</li></ul><h2 id="解锁内容" tabindex="-1">解锁内容 <a class="header-anchor" href="#解锁内容" aria-label="Permalink to &quot;解锁内容&quot;">​</a></h2><table tabindex="0"><thead><tr><th>好感度等级</th><th>可解锁内容</th></tr></thead><tbody><tr><td>1</td><td>基础互动对话</td></tr><tr><td>2</td><td>第一段专属剧情</td></tr><tr><td>3</td><td>新增语音台词</td></tr><tr><td>4</td><td>属性加成（少量）</td></tr><tr><td>5</td><td>第二段专属剧情</td></tr><tr><td>6</td><td>额外语音台词</td></tr><tr><td>7</td><td>属性加成（中等）</td></tr><tr><td>8</td><td>第三段专属剧情</td></tr><tr><td>9</td><td>特殊外观内容（表情、资料装饰等）</td></tr><tr><td>10</td><td>最终专属剧情及满级属性加成</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">INFO</p><p>各等级所需的具体好感度点数会随版本更新调整。高等级所需点数远高于低等级。</p></div>',10)])])}const u=r(o,[["render",l]]);export{_ as __pageData,u as default};
